let _pswpPromise=null;async function getPswpElement(){const e=document.querySelector("[data-photoswipe]");if(e)return e;if(!_pswpPromise){const n=document.querySelector("[data-photoswipe-url]").dataset.photoswipeUrl;_pswpPromise=fetch(n).then(t=>t.text()).then(t=>{const o=document.createElement("div");return o.innerHTML=t,document.body.appendChild(o.firstElementChild),document.querySelector("[data-photoswipe]")}).catch(t=>{console.error("[xprez] Failed to load PhotoSwipe element:",t),_pswpPromise=null})}return _pswpPromise}async function openPhotoSwipe(e,n){const t=e.map(i=>({src:i.dataset.original_url,w:parseInt(i.dataset.original_width),h:parseInt(i.dataset.original_height),title:i.dataset.title})),o={history:!1,focus:!1,showAnimationDuration:0,hideAnimationDuration:0,index:n,shareEl:!1},a=await getPswpElement();a&&new PhotoSwipe(a,PhotoSwipeUI_Default,t,o).init()}function initGallery(){const e=Array.from(document.querySelectorAll(".js-photo"));e.forEach((n,t)=>{n.addEventListener("click",o=>{o.preventDefault(),openPhotoSwipe(e,t)})})}document.addEventListener("DOMContentLoaded",initGallery);
